const recipes=[
{name:"Spaghetti Carbonara",image:"Images/spaghetti.png",ingredients:["1 lb spaghetti","3 large eggs","6 slices bacon, chopped","1 cup grated parmesan","1 tsp black pepper","1 tbsp salt (for pasta water)"],instructions:"Bring a large pot of salted water to a boil. Cook 1 lb spaghetti until al dente, about 9 minutes. Reserve 1 cup pasta water before draining. While pasta cooks, cook chopped bacon in a large skillet over medium heat until crispy, about 6-8 minutes. In a bowl, whisk together 3 eggs, 1 cup parmesan, and 1 tsp black pepper. Drain pasta and add to the skillet with bacon (heat OFF). Pour egg mixture over hot pasta and toss vigorously for 2 minutes, adding splashes of pasta water until you get a creamy, glossy sauce. Serve immediately with extra parmesan on top.",cat:"dinner",time:"25 min",diff:"Medium",emoji:"🍝"},
{name:"Pancakes",image:"Images/pancakes.png",ingredients:["1½ cups all-purpose flour","3½ tsp baking powder","1 tbsp sugar","¼ tsp salt","1¼ cups milk","1 large egg","3 tbsp melted butter"],instructions:"In a large bowl, whisk together 1½ cups flour, 3½ tsp baking powder, 1 tbsp sugar, and ¼ tsp salt. Make a well in the center and pour in 1¼ cups milk, 1 egg, and 3 tbsp melted butter. Mix until smooth. Heat a lightly oiled griddle or pan over medium-high heat. Pour about ¼ cup batter per pancake onto the griddle. Cook until bubbles form on the surface and edges look set, about 2-3 minutes. Flip and cook until golden brown on the other side, about 1-2 minutes more. Makes about 8 pancakes.",cat:"breakfast",time:"15 min",diff:"Easy",emoji:"🥞"},
{name:"Omelette",image:"Images/omelette.png",ingredients:["3 large eggs","2 tbsp milk","¼ cup shredded cheese","2 tbsp diced onion","2 tbsp diced bell pepper","1 tbsp butter","salt and pepper to taste"],instructions:"Crack 3 eggs into a bowl, add 2 tbsp milk, a pinch of salt and pepper, and whisk until well combined. Heat 1 tbsp butter in a non-stick skillet over medium heat. Pour in egg mixture and let it cook undisturbed for about 1 minute until edges start to set. Gently push cooked edges toward the center, tilting the pan so uncooked egg fills the gaps. When the top is still slightly moist but mostly set, add ¼ cup cheese, 2 tbsp diced onion, and 2 tbsp diced pepper to one half. Fold the other half over the filling. Cook 30 more seconds. Slide onto a plate and serve hot.",cat:"breakfast",time:"10 min",diff:"Easy",emoji:"🍳"},
{name:"Spiderweb Cheesecake",image:"Images/spiderweb_cheesecake.png",ingredients:["1 envelope unflavored gelatin","¼ cup cold water","2 packages (8 oz each) cream cheese, softened","½ cup sugar","1 cup heavy whipping cream","1 tsp vanilla","1 chocolate crumb crust","½ cup semisweet chocolate chips","1 tbsp butter"],instructions:"Sprinkle 1 envelope gelatin over ¼ cup cold water and let stand 5 minutes. Microwave 30 seconds to dissolve. Beat 16 oz cream cheese and ½ cup sugar with a mixer until smooth. Whip 1 cup heavy cream to stiff peaks in a separate bowl. Fold whipped cream into cream cheese mixture along with 1 tsp vanilla and dissolved gelatin. Pour filling into the chocolate crumb crust and smooth the top. Melt ½ cup chocolate chips with 1 tbsp butter in the microwave in 30-second intervals, stirring until smooth. Drizzle chocolate in concentric circles on top of the cheesecake. Drag a toothpick from center outward to create a spiderweb pattern. Refrigerate at least 4 hours or overnight before serving.",cat:"dessert",time:"45 min",diff:"Medium",emoji:"🕸️"},
{name:"Spider Cookies (No-Bake)",image:"Images/spider_cookies.png",ingredients:["2 cups sugar","½ cup cocoa powder","½ cup butter","½ cup milk","½ cup peanut butter","1 tsp vanilla","3 cups quick oats"],instructions:"In a medium saucepan, combine 2 cups sugar, ½ cup cocoa, ½ cup butter, and ½ cup milk. Bring to a rolling boil over medium heat, stirring constantly. Boil for exactly 1 minute. Remove from heat and immediately stir in ½ cup peanut butter and 1 tsp vanilla until smooth. Fold in 3 cups quick oats and stir until everything is well coated. Drop by heaping tablespoonfuls onto wax paper. Let cool completely at room temperature until set, about 30 minutes. Makes about 30 cookies.",cat:"nobake",time:"20 min",diff:"Easy",emoji:"🕷️"},
{name:"PB Marshmallow Bars",image:"Images/marshmallow.png",ingredients:["½ cup butter","½ cup peanut butter","1 cup butterscotch chips","4 cups colored mini marshmallows"],instructions:"In a large saucepan over low heat, melt ½ cup butter, ½ cup peanut butter, and 1 cup butterscotch chips together, stirring frequently until smooth and combined. Remove from heat and let cool for 5 minutes — this is important so the marshmallows don't melt completely. Fold in 4 cups colored mini marshmallows, stirring gently to coat. Spread mixture into a greased 9x13 inch pan. Press down lightly with a greased spatula. Refrigerate for at least 2 hours until firm. Cut into bars. Makes about 24 bars.",cat:"nobake",time:"15 min",diff:"Easy",emoji:"🟡"},
{name:"No-Bake Cherry Cheesecake",image:"Images/cheesecake.png",ingredients:["2 packages (8 oz each) cream cheese, softened","¾ cup sugar","1 tub (8 oz) whipped topping, thawed","1 graham cracker crust (9 inch)","1 can (21 oz) cherry pie filling"],instructions:"Beat 16 oz softened cream cheese and ¾ cup sugar with an electric mixer on medium speed until smooth and creamy, about 3 minutes. Gently fold in 8 oz thawed whipped topping with a rubber spatula until no streaks remain. Spread the filling evenly into the 9-inch graham cracker crust. Spoon 21 oz cherry pie filling over the top, spreading gently to the edges. Refrigerate for at least 4 hours or overnight until set and firm. Slice and serve cold. Serves 8.",cat:"nobake",time:"20 min",diff:"Easy",emoji:"🍒"},
{name:"Vanilla Apple Crisp with Caramel Sauce",image:"Images/apple _crisp.png",ingredients:["6 medium apples, peeled and sliced","¼ cup sugar","1 vanilla bean, split (or 2 tsp vanilla extract)","1 tbsp lemon juice","¼ tsp nutmeg","¾ cup flour","¾ cup rolled oats","¾ cup packed brown sugar","1 tsp cinnamon","⅓ cup cold butter, cubed"],instructions:"Preheat oven to 350°F. Toss 6 sliced apples with ¼ cup sugar, vanilla bean seeds (or 2 tsp extract), 1 tbsp lemon juice, and ¼ tsp nutmeg. Spread into a greased 9x13 inch baking dish. In a separate bowl, mix ¾ cup flour, ¾ cup oats, ¾ cup brown sugar, and 1 tsp cinnamon. Cut in ⅓ cup cold cubed butter with a fork or pastry cutter until the mixture resembles coarse crumbs. Sprinkle the topping evenly over the apples. Bake at 350°F for 35-45 minutes until the topping is golden brown and the apples are bubbling. Let cool 10 minutes before serving.",cat:"dessert",time:"50 min",diff:"Medium",emoji:"🍎"},
{name:"Chocolate Chunk Cookies",image:"Images/Chocolate Chunk Cookies.png",ingredients:["¾ cup margarine, softened","¾ cup packed brown sugar","½ cup white sugar","1 tsp vanilla","2 large eggs","2 cups flour","¼ cup cocoa powder","1 tsp baking soda","1 cup semi-sweet chocolate chips","½ cup chopped nuts"],instructions:"Preheat oven to 350°F. Cream ¾ cup softened margarine, ¾ cup brown sugar, and ½ cup white sugar until light and fluffy, about 3 minutes. Beat in 2 eggs one at a time and 1 tsp vanilla. In a separate bowl, whisk together 2 cups flour, ¼ cup cocoa, and 1 tsp baking soda. Gradually add dry ingredients to wet, mixing until just combined. Fold in 1 cup chocolate chips and ½ cup chopped nuts. Drop rounded tablespoonfuls onto ungreased cookie sheets, spacing 2 inches apart. Bake at 350°F for 10-12 minutes. Cool on sheet 2 minutes, then transfer to a wire rack. Makes about 36 cookies.",cat:"dessert",time:"30 min",diff:"Easy",emoji:"🍪"},
{name:"Cinnamon Rolls",image:"Images/cinnamon_rolls.png",ingredients:["2 cups flour","1 tbsp baking powder","½ tsp salt","3 tbsp cold butter (for dough)","¾ cup milk","3 tbsp softened butter (for filling)","⅓ cup packed brown sugar","2 tsp cinnamon"],instructions:"Preheat oven to 425°F. Whisk 2 cups flour, 1 tbsp baking powder, and ½ tsp salt. Cut in 3 tbsp cold butter until the mixture looks like coarse crumbs. Stir in ¾ cup milk until a soft dough forms. Turn dough onto a floured surface and knead gently 4-5 times. Roll into a 12x9 inch rectangle. Spread 3 tbsp softened butter over the surface. Mix ⅓ cup brown sugar with 2 tsp cinnamon and sprinkle evenly over the butter. Roll up tightly starting from the long side. Cut into 12 equal slices. Place cut-side down in a greased 9-inch round pan. Bake at 425°F for 14-16 minutes until golden. Serve warm.",cat:"breakfast",time:"30 min",diff:"Medium",emoji:"🌀"},
{name:"PB Cookies",image:"Images/pb_Cookies.png",ingredients:["1 large egg","1 cup sugar","1 cup peanut butter"],instructions:"Preheat oven to 325°F. In a bowl, mix together 1 egg, 1 cup sugar, and 1 cup peanut butter until a thick dough forms. Roll dough into 1-inch balls and place on parchment-lined cookie sheets, spacing 2 inches apart. Flatten each ball with a fork in a criss-cross pattern. Bake at 325°F for 18-20 minutes until edges are lightly golden but centers still look slightly soft. Let cool on sheet for 5 minutes before transferring to a wire rack. Makes about 24 cookies.",cat:"dessert",time:"25 min",diff:"Easy",emoji:"🥜"},
{name:"Caramel Popcorn Balls",image:"Images/caramel_popcorn_balls.png",ingredients:["12 cups popped popcorn","1 cup packed brown sugar","½ cup water","¼ cup butter"],instructions:"Pop enough kernels to make 12 cups popcorn and place in a very large bowl. In a saucepan, combine 1 cup brown sugar and ½ cup water. Stir over medium heat until sugar dissolves completely. Stir in ¼ cup butter until melted. Bring to a boil and cook without stirring until mixture reaches 250°F on a candy thermometer (hard ball stage), about 5 minutes. Pour hot caramel over popcorn and stir quickly with a greased spatula to coat evenly. When cool enough to handle, butter your hands and shape mixture into balls about 3 inches across. Place on wax paper to cool and harden. Makes about 10 balls.",cat:"snack",time:"20 min",diff:"Easy",emoji:"🍿"},
{name:"Chicken Balls",image:"Images/Chicken_Balls.png",ingredients:["2 lbs boneless skinless chicken breasts","2 cups pancake mix","1 cup water","peanut oil for deep-frying"],instructions:"Place 2 lbs chicken breasts in a pot, cover with water, and bring to a boil. Reduce heat and simmer for 20 minutes until cooked through. Remove chicken, let cool, then cut into 1-inch chunks. In a bowl, mix 2 cups pancake mix with 1 cup water to form a smooth batter. Heat 2-3 inches peanut oil in a deep pot to 375°F. Dip chicken chunks into the batter, letting excess drip off. Carefully lower into hot oil and fry in batches for 3-4 minutes until golden brown and crispy. Drain on paper towels. Serve hot with your favorite dipping sauce.",cat:"dinner",time:"35 min",diff:"Medium",emoji:"🍗"},
{name:"Bubbly Bake",image:"Images/Bubbly_Bake.png",ingredients:["1 bag (30 oz) frozen hashbrowns","1 can (10.5 oz) cream of chicken soup","6 slices bacon, cooked and crumbled","1 cup sour cream","1 can (6 oz) French fried onions"],instructions:"Preheat oven to 375°F. Thaw 30 oz hashbrowns slightly. In a large bowl, mix hashbrowns, 1 can cream of chicken soup, crumbled bacon from 6 cooked slices, and 1 cup sour cream until well combined. Spread mixture into a greased 9x13 inch baking dish. Top evenly with 6 oz French fried onions. Cover with foil and bake at 375°F for 25 minutes. Remove foil and bake another 15 minutes until the top is golden and bubbly. Let rest 5 minutes before serving. Serves 8.",cat:"dinner",time:"50 min",diff:"Easy",emoji:"🧀"},
{name:"Meatballs",image:"Images/michelles_meatballs.png",ingredients:["1½ lbs ground beef","3 cloves garlic, minced","1 tbsp Italian seasoning","½ tsp chili pepper flakes","½ cup finely diced onions","1 large egg","⅓ cup bread crumbs","½ tsp salt","¼ tsp pepper"],instructions:"Preheat oven to 350°F. In a large bowl, combine 1½ lbs ground beef, 3 cloves minced garlic, 1 tbsp Italian seasoning, ½ tsp chili flakes, ½ cup diced onions, 1 egg, ⅓ cup bread crumbs, ½ tsp salt, and ¼ tsp pepper. Mix with your hands until everything is evenly combined — don't overmix. Roll mixture into golf ball-sized meatballs (about 1½ inches). Place on a parchment-lined baking sheet, spaced 1 inch apart. Bake at 350°F for 20-25 minutes until browned and cooked through (internal temp 165°F). Makes about 24 meatballs.",cat:"dinner",time:"30 min",diff:"Easy",emoji:"🧆"},
{name:"Nana's Chicken",image:"Images/nanas_Chicken.png",ingredients:["2 lbs chicken pieces","1 large egg","½ cup milk","1 cup flour","1 cup bread crumbs","1 tsp garlic salt","1 tsp garlic powder","½ tsp pepper"],instructions:"In a shallow bowl, whisk together 1 egg and ½ cup milk. In another shallow bowl, combine 1 cup flour, 1 cup bread crumbs, 1 tsp garlic salt, 1 tsp garlic powder, and ½ tsp pepper. Dip each piece of chicken (about 2 lbs total) into the egg/milk mixture, letting excess drip off. Then press firmly into the flour/breadcrumb mixture, coating all sides well. Place on a greased baking sheet. Bake at 375°F for 35-40 minutes, flipping halfway, until golden brown and chicken reaches an internal temperature of 165°F. Alternatively, pan-fry in ½ inch of oil over medium-high heat, about 6-8 minutes per side.",cat:"dinner",time:"45 min",diff:"Medium",emoji:"🍗"},
{name:"Classic Mac & Cheese",image:"",ingredients:["8 oz elbow macaroni","3 tbsp butter","3 tbsp flour","2½ cups milk","3 cups shredded sharp cheddar","½ tsp salt","¼ tsp pepper","¼ tsp paprika"],instructions:"Cook 8 oz macaroni according to package directions and drain. In a large saucepan, melt 3 tbsp butter over medium heat. Whisk in 3 tbsp flour and cook 1 minute. Gradually add 2½ cups milk, whisking constantly. Cook until thickened, about 5 minutes. Remove from heat and stir in 2½ cups cheddar, ½ tsp salt, ¼ tsp pepper, and ¼ tsp paprika until cheese is melted. Add cooked macaroni and stir to combine. Transfer to a greased 2-quart baking dish, top with remaining ½ cup cheddar. Bake at 375°F for 20 minutes until bubbly and golden. Serves 6.",cat:"dinner",time:"35 min",diff:"Easy",emoji:"🧀"},
{name:"Grilled Cheese Sandwich",image:"",ingredients:["2 slices bread","1 tbsp butter","2 slices cheddar cheese","2 slices mozzarella"],instructions:"Butter one side of each bread slice. Place one slice butter-side down in a skillet over medium heat. Layer 2 slices cheddar and 2 slices mozzarella on top. Place second bread slice on top, butter-side up. Cook 3-4 minutes until the bottom is golden brown. Carefully flip and cook another 2-3 minutes until the second side is golden and cheese is fully melted. Slice in half diagonally and serve immediately. Serves 1.",cat:"lunch",time:"10 min",diff:"Easy",emoji:"🥪"},
{name:"Tomato Soup",image:"",ingredients:["1 can (28 oz) whole peeled tomatoes","1 medium onion, diced","3 cloves garlic, minced","2 cups chicken broth","2 tbsp butter","½ cup heavy cream","¼ cup fresh basil, chopped","½ tsp salt","¼ tsp pepper"],instructions:"Melt 2 tbsp butter in a large pot over medium heat. Add diced onion and cook 5 minutes until softened. Add 3 cloves minced garlic and cook 1 minute. Pour in 28 oz canned tomatoes (with juices) and 2 cups chicken broth. Bring to a boil, then reduce heat and simmer 20 minutes. Use an immersion blender (or transfer to a blender in batches) and blend until smooth. Stir in ½ cup heavy cream, ¼ cup chopped basil, ½ tsp salt, and ¼ tsp pepper. Heat through for 2 more minutes. Serve with grilled cheese. Serves 4.",cat:"soup",time:"30 min",diff:"Easy",emoji:"🍅"},
{name:"Caesar Salad",image:"",ingredients:["1 large head romaine lettuce, chopped","½ cup shaved parmesan","1 cup croutons","3 tbsp lemon juice","¼ cup olive oil","2 cloves garlic, minced","1 tsp Worcestershire sauce","1 tsp Dijon mustard","1 anchovy (or ½ tsp anchovy paste)"],instructions:"Whisk together 3 tbsp lemon juice, ¼ cup olive oil, 2 cloves minced garlic, 1 tsp Worcestershire, 1 tsp Dijon mustard, and 1 minced anchovy until well combined. Chop 1 large head of romaine into bite-sized pieces and place in a large bowl. Pour dressing over lettuce and toss thoroughly. Add 1 cup croutons and ½ cup shaved parmesan. Toss again gently. Serve immediately as a side or add grilled chicken for a main. Serves 4.",cat:"salad",time:"15 min",diff:"Easy",emoji:"🥗"},
{name:"Chicken Alfredo",image:"",ingredients:["12 oz fettuccine","2 chicken breasts","3 tbsp butter","3 cloves garlic, minced","1½ cups heavy cream","1½ cups grated parmesan","½ tsp salt","¼ tsp pepper","2 tbsp fresh parsley, chopped"],instructions:"Season 2 chicken breasts with salt and pepper. Cook in 1 tbsp butter in a skillet over medium-high heat, about 6-7 minutes per side until golden and cooked through (internal temp 165°F). Let rest 5 minutes, then slice. Cook 12 oz fettuccine according to package directions. In the same skillet, melt 2 tbsp butter over medium heat. Add 3 cloves minced garlic and cook 30 seconds. Pour in 1½ cups heavy cream, bring to a gentle simmer. Stir in 1½ cups parmesan, ½ tsp salt, and ¼ tsp pepper until smooth. Toss drained pasta in the sauce. Top with sliced chicken and parsley. Serves 4.",cat:"dinner",time:"30 min",diff:"Medium",emoji:"🍝"},
{name:"Beef Tacos",image:"",ingredients:["1 lb ground beef","1 packet (1 oz) taco seasoning","½ cup water","8 taco shells","1 cup shredded lettuce","1 medium tomato, diced","1 cup shredded cheddar","½ cup sour cream","½ cup salsa"],instructions:"Brown 1 lb ground beef in a skillet over medium-high heat, breaking it up as it cooks, about 6-8 minutes. Drain excess grease. Add 1 packet taco seasoning and ½ cup water. Stir and simmer 5 minutes until sauce thickens. Warm 8 taco shells according to package directions. Fill each shell with seasoned beef and top with shredded lettuce, diced tomato, shredded cheddar, a dollop of sour cream, and salsa. Serves 4 (2 tacos each).",cat:"dinner",time:"20 min",diff:"Easy",emoji:"🌮"},
{name:"Banana Bread",image:"",ingredients:["3 ripe bananas, mashed (about 1¼ cups)","⅓ cup melted butter","¾ cup sugar","1 large egg","1 tsp vanilla","1 tsp baking soda","¼ tsp salt","1½ cups all-purpose flour"],instructions:"Preheat oven to 350°F. Grease an 8x4 inch loaf pan. Mash 3 ripe bananas in a large bowl. Stir in ⅓ cup melted butter, ¾ cup sugar, 1 egg, and 1 tsp vanilla until combined. Mix in 1 tsp baking soda and ¼ tsp salt. Gently fold in 1½ cups flour until just combined — lumps are fine, don't overmix. Pour batter into the greased loaf pan. Bake at 350°F for 55-60 minutes until a toothpick inserted in the center comes out clean and the top is deep golden brown. Cool in pan 10 minutes, then turn out onto a wire rack. Serves 8-10 slices.",cat:"dessert",time:"65 min",diff:"Easy",emoji:"🍌"},
{name:"French Toast",image:"",ingredients:["4 thick slices bread","2 large eggs","⅓ cup milk","1 tsp cinnamon","½ tsp vanilla","2 tbsp butter","maple syrup for serving"],instructions:"Whisk together 2 eggs, ⅓ cup milk, 1 tsp cinnamon, and ½ tsp vanilla in a shallow bowl. Melt 1 tbsp butter in a skillet over medium heat. Dip each slice of bread into the egg mixture, soaking each side for about 10 seconds. Place in the hot skillet and cook 2-3 minutes per side until golden brown. Add remaining butter as needed for the second batch. Serve immediately with maple syrup, fresh berries, or powdered sugar. Serves 2.",cat:"breakfast",time:"15 min",diff:"Easy",emoji:"🍞"},
{name:"Chicken Noodle Soup",image:"",ingredients:["2 chicken breasts","8 oz egg noodles","3 medium carrots, sliced","3 stalks celery, sliced","1 medium onion, diced","3 cloves garlic, minced","8 cups chicken broth","1 tsp dried thyme","2 bay leaves","1 tsp salt","½ tsp pepper"],instructions:"Place 2 chicken breasts in a large pot with 8 cups broth. Bring to a boil, reduce heat and simmer 20 minutes until chicken is cooked through. Remove chicken and shred with two forks. In the same pot, add 1 diced onion, 3 sliced carrots, 3 sliced celery stalks, and 3 cloves minced garlic. Add 1 tsp thyme, 2 bay leaves, 1 tsp salt, ½ tsp pepper. Simmer 10 minutes until vegetables are tender. Add 8 oz egg noodles and cook 6-8 minutes. Return shredded chicken to the pot. Remove bay leaves. Taste and adjust seasoning. Serves 6.",cat:"soup",time:"45 min",diff:"Easy",emoji:"🍜"},
{name:"BLT Sandwich",image:"",ingredients:["6 slices bacon","2 leaves romaine lettuce","1 medium tomato, sliced","4 slices bread","2 tbsp mayonnaise"],instructions:"Cook 6 slices of bacon in a skillet over medium heat until crispy, about 8-10 minutes. Drain on paper towels. Toast 4 slices of bread. Spread 2 tbsp mayonnaise evenly on one side of each toast. Layer 3 slices bacon, a lettuce leaf, and 2-3 tomato slices on 2 of the toasts. Top with the remaining toasts, mayo-side down. Cut each sandwich diagonally and serve immediately. Makes 2 sandwiches.",cat:"lunch",time:"12 min",diff:"Easy",emoji:"🥓"},
{name:"Chocolate Brownies",image:"",ingredients:["½ cup butter","1 cup sugar","2 large eggs","1 tsp vanilla","⅓ cup cocoa powder","½ cup all-purpose flour","¼ tsp salt","¼ tsp baking powder","½ cup chocolate chips"],instructions:"Preheat oven to 350°F. Grease an 8x8 inch pan. Melt ½ cup butter, then stir in 1 cup sugar. Beat in 2 eggs and 1 tsp vanilla. In a separate bowl, whisk ⅓ cup cocoa, ½ cup flour, ¼ tsp salt, and ¼ tsp baking powder. Fold dry ingredients into wet until just combined. Stir in ½ cup chocolate chips. Pour into prepared pan and spread evenly. Bake at 350°F for 25-28 minutes — a toothpick should come out with a few moist crumbs, not wet batter. Cool in pan at least 20 minutes before cutting into 16 squares.",cat:"dessert",time:"35 min",diff:"Easy",emoji:"🍫"},
{name:"Garlic Bread",image:"",ingredients:["1 French baguette","¼ cup softened butter","4 cloves garlic, minced","2 tbsp fresh parsley, chopped","¼ cup grated parmesan"],instructions:"Preheat oven to 375°F. Cut baguette in half lengthwise. In a small bowl, mix ¼ cup softened butter, 4 cloves minced garlic, 2 tbsp chopped parsley, and ¼ cup grated parmesan. Spread the butter mixture generously over both cut halves of the baguette. Place on a baking sheet cut-side up. Bake at 375°F for 10-12 minutes until the edges are golden and crispy and the butter is melted and bubbly. Slice into pieces and serve warm. Serves 6-8.",cat:"side",time:"15 min",diff:"Easy",emoji:"🧄"},
{name:"Chicken Quesadilla",image:"",ingredients:["2 large flour tortillas","1 cup cooked shredded chicken","1 cup shredded cheddar cheese","¼ cup diced bell peppers","2 tbsp diced onion","salsa for serving","sour cream for serving"],instructions:"Place 1 tortilla in a dry skillet over medium heat. Spread ½ cup shredded chicken, ½ cup cheddar, 2 tbsp diced peppers, and 1 tbsp diced onion over one half. Fold the tortilla in half. Cook 3 minutes until the bottom is golden and crispy. Flip carefully and cook another 2-3 minutes until cheese is fully melted. Repeat with second tortilla. Cut each quesadilla into 3 wedges. Serve with salsa and sour cream. Serves 2.",cat:"dinner",time:"15 min",diff:"Easy",emoji:"🫓"},
{name:"Mashed Potatoes",image:"",ingredients:["3 lbs russet potatoes, peeled and cubed","4 tbsp butter","½ cup warm milk","2 cloves garlic, minced","1 tsp salt","¼ tsp pepper"],instructions:"Peel and cut 3 lbs potatoes into 1-inch cubes. Place in a large pot, cover with cold water by 1 inch, and add a generous pinch of salt. Bring to a boil and cook 15-20 minutes until fork-tender. Drain well and return to the pot. Add 4 tbsp butter, ½ cup warm milk, 2 cloves minced garlic, 1 tsp salt, and ¼ tsp pepper. Mash with a potato masher until smooth and fluffy, adding more milk if needed. Taste and adjust seasoning. Serves 6.",cat:"side",time:"25 min",diff:"Easy",emoji:"🥔"},
{name:"Strawberry Smoothie",image:"",ingredients:["1 cup frozen strawberries","1 ripe banana","½ cup plain yogurt","½ cup milk","1 tbsp honey"],instructions:"Add 1 cup frozen strawberries, 1 banana, ½ cup yogurt, ½ cup milk, and 1 tbsp honey to a blender. Blend on high for 45-60 seconds until completely smooth and creamy. Pour into a tall glass. Adjust thickness by adding more milk (thinner) or frozen fruit (thicker). Serves 1 large glass.",cat:"drink",time:"5 min",diff:"Easy",emoji:"🍓"},
{name:"Chili",image:"",ingredients:["2 lbs ground beef","1 large onion, diced","3 cloves garlic, minced","1 can (28 oz) crushed tomatoes","1 can (15 oz) kidney beans, drained","2 tbsp chili powder","1 tbsp cumin","1 tsp paprika","½ tsp salt","¼ tsp pepper","1 cup beef broth"],instructions:"Heat a large pot or Dutch oven over medium-high heat. Add 2 lbs ground beef, breaking up with a wooden spoon. Cook 8-10 minutes until browned. Drain excess fat. Add 1 diced onion and cook 4-5 minutes until softened. Add 3 cloves minced garlic and cook 1 minute. Stir in 2 tbsp chili powder, 1 tbsp cumin, and 1 tsp paprika. Cook 1 minute until fragrant. Add 28 oz crushed tomatoes, 15 oz drained kidney beans, 1 cup beef broth, ½ tsp salt, and ¼ tsp pepper. Stir and bring to a boil. Reduce heat and simmer uncovered 30-40 minutes, stirring occasionally, until thickened. Top with cheddar, sour cream, and green onions. Serves 6-8.",cat:"soup",time:"50 min",diff:"Easy",emoji:"🌶️"},
{name:"Fried Rice",image:"",ingredients:["3 cups cold cooked rice","2 large eggs, beaten","3 tbsp soy sauce","1 tbsp sesame oil","½ cup frozen peas","½ cup diced carrots","3 green onions, sliced","3 cloves garlic, minced"],instructions:"Heat 1 tbsp sesame oil in a large skillet or wok over high heat. Scramble 2 beaten eggs, breaking into small pieces. Set aside. Add another 1 tbsp oil to the pan. Add ½ cup diced carrots and cook 2 minutes. Add 3 cloves minced garlic and cook 30 seconds. Add 3 cups cold rice, breaking up clumps. Stir-fry 3-4 minutes until rice is hot and slightly crispy. Add ½ cup peas, scrambled eggs, and 3 tbsp soy sauce. Toss everything together for 1-2 minutes. Garnish with sliced green onions. Serves 4.",cat:"dinner",time:"15 min",diff:"Easy",emoji:"🍚"},
{name:"Guacamole",image:"",ingredients:["3 ripe avocados","2 tbsp fresh lime juice","½ tsp salt","½ cup diced onion","3 tbsp fresh cilantro, chopped","1 small jalapeño, seeded and minced","1 medium tomato, diced","1 clove garlic, minced"],instructions:"Cut 3 avocados in half, remove pits, and scoop flesh into a bowl. Add 2 tbsp lime juice and ½ tsp salt. Mash with a fork to your desired consistency — chunky or smooth. Fold in ½ cup diced onion, 3 tbsp chopped cilantro, 1 minced jalapeño, 1 diced tomato, and 1 minced clove garlic. Stir gently. Taste and adjust salt and lime as needed. Cover with plastic wrap pressed directly onto the surface (to prevent browning) and refrigerate until serving. Best eaten within a few hours. Serves 6.",cat:"appetizer",time:"10 min",diff:"Easy",emoji:"🥑"},
{name:"BBQ Pulled Pork Sliders",image:"",ingredients:["3 lbs pork shoulder","1½ cups BBQ sauce","12 slider buns","1 cup prepared coleslaw","2 tbsp apple cider vinegar","2 tbsp brown sugar","1 tsp salt","½ tsp pepper","1 tsp garlic powder","1 tsp onion powder"],instructions:"Season 3 lbs pork shoulder with 1 tsp salt, ½ tsp pepper, 1 tsp garlic powder, and 1 tsp onion powder. Place in a slow cooker. Pour ½ cup BBQ sauce and 2 tbsp apple cider vinegar over the top. Cover and cook on LOW for 8 hours or HIGH for 4 hours until pork shreds easily. Remove pork, shred with two forks, and discard any large fat pieces. Return shredded pork to the slow cooker. Stir in remaining 1 cup BBQ sauce and 2 tbsp brown sugar. Cook another 15 minutes. Pile pork onto 12 slider buns and top with coleslaw. Serves 6 (2 sliders each).",cat:"dinner",time:"8 hrs",diff:"Medium",emoji:"🐷"},
{name:"Veggie Stir Fry",image:"",ingredients:["2 cups broccoli florets","1 red bell pepper, sliced","1 cup snap peas","2 medium carrots, sliced thin","3 tbsp soy sauce","1 tbsp sesame oil","3 cloves garlic, minced","1 tsp fresh ginger, grated","1 tbsp cornstarch","2 tbsp water"],instructions:"Mix 3 tbsp soy sauce, 1 tbsp sesame oil, 1 tbsp cornstarch, and 2 tbsp water in a small bowl to make the sauce. Heat 1 tbsp oil in a large skillet or wok over high heat. Add 3 cloves minced garlic and 1 tsp grated ginger, stir 30 seconds. Add 2 sliced carrots and cook 2 minutes. Add 2 cups broccoli, 1 sliced bell pepper, and 1 cup snap peas. Stir-fry 4-5 minutes until vegetables are tender-crisp and bright. Pour sauce over vegetables and toss 1-2 minutes until the sauce thickens and coats everything. Serve over steamed rice. Serves 4.",cat:"dinner",time:"15 min",diff:"Easy",emoji:"🥦"},
{name:"Deviled Eggs",image:"",ingredients:["12 large eggs","½ cup mayonnaise","2 tsp yellow mustard","1 tsp white vinegar","½ tsp salt","¼ tsp pepper","paprika for garnish"],instructions:"Place 12 eggs in a single layer in a pot. Cover with cold water by 1 inch. Bring to a boil, then cover and remove from heat. Let sit 12 minutes. Transfer eggs to an ice bath for 5 minutes. Peel eggs and slice in half lengthwise. Scoop yolks into a bowl. Mash yolks with a fork, then mix in ½ cup mayo, 2 tsp mustard, 1 tsp vinegar, ½ tsp salt, and ¼ tsp pepper until smooth and creamy. Pipe or spoon the yolk filling back into the egg white halves. Sprinkle with paprika. Refrigerate until serving. Makes 24 deviled egg halves.",cat:"appetizer",time:"25 min",diff:"Easy",emoji:"🥚"},
{name:"Chicken Caesar Wrap",image:"",ingredients:["2 large flour tortillas","1 grilled chicken breast, sliced","2 cups chopped romaine lettuce","¼ cup shaved parmesan","3 tbsp Caesar dressing","½ cup croutons"],instructions:"Lay 2 tortillas flat. Spread 1½ tbsp Caesar dressing down the center of each. Divide 1 sliced grilled chicken breast, 2 cups chopped romaine, ¼ cup shaved parmesan, and ½ cup croutons between the two tortillas. Fold the sides of each tortilla inward, then roll up tightly from the bottom. Cut each wrap in half diagonally. Serve immediately. Makes 2 wraps.",cat:"lunch",time:"10 min",diff:"Easy",emoji:"🌯"},
{name:"Blueberry Muffins",image:"",ingredients:["2 cups all-purpose flour","¾ cup sugar","2½ tsp baking powder","½ tsp salt","⅓ cup vegetable oil","1 large egg","1 cup milk","1 tsp vanilla","1 cup fresh blueberries"],instructions:"Preheat oven to 375°F. Line a 12-cup muffin tin with paper liners. Whisk together 2 cups flour, ¾ cup sugar, 2½ tsp baking powder, and ½ tsp salt. In a separate bowl, combine ⅓ cup oil, 1 egg, 1 cup milk, and 1 tsp vanilla. Pour wet ingredients into dry and stir until just combined — batter should be lumpy. Gently fold in 1 cup blueberries. Fill muffin cups about ⅔ full. Bake at 375°F for 20-22 minutes until tops are golden and a toothpick comes out clean. Cool in pan 5 minutes, then transfer to a wire rack. Makes 12 muffins.",cat:"breakfast",time:"35 min",diff:"Easy",emoji:"🫐"},
{name:"Sloppy Joes",image:"",ingredients:["1 lb ground beef","½ medium onion, diced","2 cloves garlic, minced","½ cup ketchup","2 tbsp brown sugar","1 tbsp yellow mustard","1 tbsp Worcestershire sauce","½ tsp salt","4 hamburger buns"],instructions:"Brown 1 lb ground beef in a skillet over medium-high heat, breaking it up as it cooks, about 6-8 minutes. Add ½ diced onion and 2 cloves minced garlic. Cook 3 more minutes. Drain excess grease. Stir in ½ cup ketchup, 2 tbsp brown sugar, 1 tbsp mustard, 1 tbsp Worcestershire, and ½ tsp salt. Simmer 8-10 minutes, stirring occasionally, until the sauce thickens. Spoon onto 4 toasted hamburger buns. Serves 4.",cat:"dinner",time:"20 min",diff:"Easy",emoji:"🍔"},
{name:"Rice Krispie Treats",image:"",ingredients:["3 tbsp butter","10 oz marshmallows (about 40 large)","6 cups Rice Krispies cereal","1 tsp vanilla"],instructions:"Melt 3 tbsp butter in a large pot over low heat. Add 10 oz marshmallows and stir constantly until completely melted and smooth, about 5 minutes. Remove from heat and stir in 1 tsp vanilla. Add 6 cups Rice Krispies cereal and stir quickly until all the cereal is evenly coated. Press mixture into a greased 9x13 inch pan using a greased spatula or wax paper. Let cool completely at room temperature for at least 30 minutes before cutting into squares. Makes about 16 squares.",cat:"nobake",time:"15 min",diff:"Easy",emoji:"🍚"},
{name:"Potato Soup",image:"",ingredients:["5 medium russet potatoes, peeled and cubed","6 slices bacon","1 medium onion, diced","2 cloves garlic, minced","4 cups chicken broth","1 cup heavy cream","1 cup shredded cheddar","½ cup sour cream","3 tbsp chopped chives","½ tsp salt","¼ tsp pepper"],instructions:"Cook 6 slices bacon in a large pot until crispy. Remove and crumble, set aside. In the same pot with 2 tbsp of the bacon grease, sauté 1 diced onion 4-5 minutes. Add 2 cloves minced garlic and cook 30 seconds. Add 5 cubed potatoes and 4 cups chicken broth. Bring to a boil, then simmer 15-20 minutes until potatoes are fork-tender. Use a potato masher to mash about half the potatoes (leave some chunks). Stir in 1 cup heavy cream, 1 cup cheddar, ½ cup sour cream, ½ tsp salt, and ¼ tsp pepper. Heat through 3-4 minutes. Serve topped with crumbled bacon and chives. Serves 6.",cat:"soup",time:"40 min",diff:"Easy",emoji:"🥔"},
{name:"Spinach Artichoke Dip",image:"",ingredients:["8 oz cream cheese, softened","½ cup sour cream","½ cup grated parmesan","10 oz frozen spinach, thawed and squeezed dry","1 can (14 oz) artichoke hearts, drained and chopped","2 cloves garlic, minced","1 cup shredded mozzarella"],instructions:"Preheat oven to 375°F. Mix 8 oz softened cream cheese, ½ cup sour cream, and ½ cup parmesan until smooth. Stir in 10 oz thawed and squeezed-dry spinach, 14 oz chopped artichoke hearts, and 2 cloves minced garlic. Spread into a 9-inch baking dish. Top with 1 cup shredded mozzarella. Bake at 375°F for 25 minutes until bubbly and golden on top. Serve hot with tortilla chips, crackers, or sliced baguette. Serves 8.",cat:"appetizer",time:"35 min",diff:"Easy",emoji:"🫕"},
{name:"Baked Ziti",image:"",ingredients:["1 lb ziti pasta","1 cup ricotta cheese","2 cups shredded mozzarella","½ cup grated parmesan","1 jar (24 oz) marinara sauce","1 lb Italian sausage","3 cloves garlic, minced","2 tbsp fresh basil, chopped"],instructions:"Preheat oven to 375°F. Cook 1 lb ziti according to package directions and drain. Brown 1 lb Italian sausage in a skillet over medium heat with 3 cloves minced garlic, breaking it up as it cooks, about 8 minutes. Drain fat. In a large bowl, combine cooked ziti, sausage, 24 oz marinara sauce, 1 cup ricotta, 1 cup mozzarella, and ¼ cup parmesan. Toss to combine. Spread into a greased 9x13 inch baking dish. Top with remaining 1 cup mozzarella and ¼ cup parmesan. Cover with foil. Bake 20 minutes covered, then 5 minutes uncovered until cheese is bubbly and golden. Top with fresh basil. Serves 8.",cat:"dinner",time:"45 min",diff:"Medium",emoji:"🍝"},
{name:"Fruit Salad",image:"",ingredients:["1 cup strawberries, quartered","1 cup blueberries","1 cup grapes, halved","1 can (11 oz) mandarin oranges, drained","2 kiwis, peeled and sliced","2 tbsp honey","1 tbsp fresh lime juice","6 fresh mint leaves, chopped"],instructions:"Wash and prep all fruit: quarter 1 cup strawberries, halve 1 cup grapes, peel and slice 2 kiwis, drain mandarin oranges. Combine all fruit in a large bowl with 1 cup blueberries. In a small bowl, whisk 2 tbsp honey and 1 tbsp lime juice together. Drizzle over the fruit and toss gently to coat. Garnish with chopped fresh mint. Serve immediately or refrigerate up to 2 hours. Serves 6.",cat:"side",time:"15 min",diff:"Easy",emoji:"🍇"},
{name:"Cornbread",image:"",ingredients:["1 cup yellow cornmeal","1 cup all-purpose flour","¼ cup sugar","1 tbsp baking powder","½ tsp salt","1 cup milk","1 large egg","⅓ cup melted butter","2 tbsp honey (optional glaze)"],instructions:"Preheat oven to 400°F. Grease an 8-inch square or round pan. Whisk together 1 cup cornmeal, 1 cup flour, ¼ cup sugar, 1 tbsp baking powder, and ½ tsp salt. In a separate bowl, combine 1 cup milk, 1 egg, and ⅓ cup melted butter. Pour wet into dry and stir until just combined — don't overmix. Pour batter into the greased pan. Bake at 400°F for 20-25 minutes until the top is golden and a toothpick comes out clean. Brush with 2 tbsp honey while still warm if desired. Serves 9.",cat:"side",time:"30 min",diff:"Easy",emoji:"🌽"},
{name:"Egg Salad Sandwich",image:"",ingredients:["6 large eggs","¼ cup mayonnaise","1 tsp yellow mustard","2 tbsp diced celery","¼ tsp salt","⅛ tsp pepper","4 slices bread","2 leaves lettuce"],instructions:"Place 6 eggs in a pot, cover with water. Bring to a boil, cover, remove from heat, and let stand 12 minutes. Transfer to ice water for 5 minutes. Peel and chop eggs. In a bowl, combine chopped eggs, ¼ cup mayo, 1 tsp mustard, 2 tbsp diced celery, ¼ tsp salt, and ⅛ tsp pepper. Mix gently. Divide egg salad between 2 slices of bread. Top each with a lettuce leaf and remaining bread. Cut in half and serve. Makes 2 sandwiches.",cat:"lunch",time:"20 min",diff:"Easy",emoji:"🥪"},
{name:"Tuna Salad",image:"",ingredients:["2 cans (5 oz each) tuna, drained","3 tbsp mayonnaise","2 tbsp diced celery","1 tbsp diced onion","1 tsp lemon juice","¼ tsp salt","⅛ tsp pepper"],instructions:"Drain 2 cans tuna well and flake into a bowl with a fork. Add 3 tbsp mayo, 2 tbsp diced celery, 1 tbsp diced onion, 1 tsp lemon juice, ¼ tsp salt, and ⅛ tsp pepper. Mix until well combined. Serve on bread, crackers, or a bed of lettuce. Can also be stuffed into a tomato or scooped into avocado halves. Keeps in the refrigerator up to 3 days. Serves 2-3.",cat:"lunch",time:"10 min",diff:"Easy",emoji:"🐟"},
{name:"Chicken Parmesan",image:"",ingredients:["2 chicken breasts, pounded to ½ inch thick","1 cup bread crumbs","½ cup grated parmesan","1 large egg, beaten","1 cup marinara sauce","1 cup shredded mozzarella","8 oz spaghetti","2 tbsp fresh basil","2 tbsp olive oil","½ tsp salt","¼ tsp pepper"],instructions:"Preheat oven to 400°F. Season 2 pounded chicken breasts with ½ tsp salt and ¼ tsp pepper. Mix 1 cup bread crumbs with ½ cup parmesan in a shallow dish. Dip chicken in beaten egg, then press into the breadcrumb mixture, coating both sides. Heat 2 tbsp olive oil in an oven-safe skillet over medium-high heat. Pan-fry chicken 3 minutes per side until golden. Spoon 1 cup marinara over the chicken. Top each breast with ½ cup mozzarella. Transfer skillet to oven and bake at 400°F for 15 minutes until cheese is melted and bubbly and chicken reaches 165°F. Meanwhile, cook 8 oz spaghetti. Serve chicken over spaghetti and garnish with fresh basil. Serves 2.",cat:"dinner",time:"40 min",diff:"Medium",emoji:"🍗"},
{name:"Homemade Pizza Dough",image:"",ingredients:["3½ cups all-purpose flour","1 packet (2¼ tsp) active dry yeast","1¼ cups warm water (110°F)","2 tbsp olive oil","1 tbsp sugar","1 tsp salt"],instructions:"In a large bowl, dissolve 1 tbsp sugar and 1 packet yeast in 1¼ cups warm water. Let sit 10 minutes until foamy. Add 2 tbsp olive oil and 1 tsp salt. Stir in 3½ cups flour, 1 cup at a time, until a shaggy dough forms. Turn onto a floured surface and knead 8-10 minutes until smooth and elastic. Place in a lightly oiled bowl, cover with a damp towel, and let rise in a warm spot 1 hour until doubled. Punch down, divide in half for 2 pizzas. Roll each portion out on a floured surface to your desired thickness. Transfer to a greased pizza pan or baking sheet. Add your favorite sauce, cheese, and toppings. Bake at 475°F for 12-15 minutes. Makes 2 medium pizzas.",cat:"dinner",time:"90 min",diff:"Medium",emoji:"🍕"},
{name:"Coleslaw",image:"",ingredients:["4 cups shredded green cabbage","1 cup shredded carrots","½ cup mayonnaise","2 tbsp apple cider vinegar","1 tbsp sugar","½ tsp salt","¼ tsp pepper"],instructions:"Finely shred 4 cups cabbage and 1 cup carrots. Place in a large bowl. In a small bowl, whisk together ½ cup mayo, 2 tbsp apple cider vinegar, 1 tbsp sugar, ½ tsp salt, and ¼ tsp pepper until smooth. Pour dressing over the cabbage and carrots and toss until everything is evenly coated. Cover and refrigerate at least 1 hour before serving to let the flavors meld. Stir again before serving. Serves 6.",cat:"side",time:"10 min",diff:"Easy",emoji:"🥬"},
{name:"Chocolate Chip Pancakes",image:"",ingredients:["1½ cups all-purpose flour","2 tbsp sugar","2 tsp baking powder","¼ tsp salt","1¼ cups milk","1 large egg","3 tbsp melted butter","1 tsp vanilla","½ cup mini chocolate chips"],instructions:"Whisk 1½ cups flour, 2 tbsp sugar, 2 tsp baking powder, and ¼ tsp salt in a large bowl. In a separate bowl, whisk 1¼ cups milk, 1 egg, 3 tbsp melted butter, and 1 tsp vanilla. Pour wet into dry and stir until just combined. Fold in ½ cup mini chocolate chips. Heat a griddle over medium heat and lightly grease. Pour ¼ cup batter per pancake. Cook until bubbles form on the surface, about 2-3 minutes. Flip and cook 1-2 more minutes until golden. Serve with maple syrup and extra chocolate chips. Makes about 10 pancakes.",cat:"breakfast",time:"18 min",diff:"Easy",emoji:"🥞"},
{name:"Hot Chocolate",image:"",ingredients:["2 cups milk","2 tbsp cocoa powder","2 tbsp sugar","½ tsp vanilla","whipped cream for topping","marshmallows for topping"],instructions:"Heat 2 cups milk in a small saucepan over medium heat until steaming but not boiling. Whisk in 2 tbsp cocoa powder and 2 tbsp sugar until fully dissolved and smooth. Stir in ½ tsp vanilla. Pour into 2 mugs. Top with whipped cream and marshmallows. Serves 2.",cat:"drink",time:"8 min",diff:"Easy",emoji:"☕"},
{name:"Chicken Fried Rice",image:"",ingredients:["3 cups cold cooked rice","1 chicken breast, diced small","2 large eggs, beaten","3 tbsp soy sauce","1 tbsp sesame oil","½ cup frozen peas","½ cup diced carrots","3 green onions, sliced","3 cloves garlic, minced","1 tsp fresh ginger, grated"],instructions:"Heat 1 tbsp oil in a large skillet over high heat. Season diced chicken with a pinch of salt. Cook 5-6 minutes until browned and cooked through. Remove and set aside. Scramble 2 beaten eggs in the same pan, breaking into small pieces. Set aside with the chicken. Add 1 tbsp sesame oil to the pan. Sauté 3 cloves minced garlic, 1 tsp grated ginger, and ½ cup diced carrots for 2 minutes. Add 3 cups cold rice and stir-fry 3-4 minutes, breaking up clumps. Add ½ cup peas, cooked chicken, eggs, and 3 tbsp soy sauce. Toss everything together 1-2 minutes. Garnish with sliced green onions. Serves 4.",cat:"dinner",time:"20 min",diff:"Easy",emoji:"🍚"},
{name:"Sugar Cookies",image:"",ingredients:["¾ cup softened butter","¾ cup sugar","1 large egg","1 tsp vanilla","2¼ cups all-purpose flour","1 tsp baking powder","¼ tsp salt"],instructions:"Cream ¾ cup softened butter and ¾ cup sugar until light and fluffy, about 3 minutes. Beat in 1 egg and 1 tsp vanilla. In a separate bowl, whisk 2¼ cups flour, 1 tsp baking powder, and ¼ tsp salt. Gradually add dry ingredients to wet, mixing until a smooth dough forms. Wrap dough in plastic and refrigerate 1 hour. Preheat oven to 350°F. Roll dough to ¼ inch thick on a floured surface. Cut with cookie cutters. Place on parchment-lined baking sheets. Bake at 350°F for 8-10 minutes until edges are barely golden — do not overbake. Cool completely before decorating with icing if desired. Makes about 24 cookies.",cat:"dessert",time:"75 min",diff:"Medium",emoji:"🍪"},
{name:"Beef Stew",image:"",ingredients:["2 lbs beef chuck, cut into 1-inch cubes","4 medium potatoes, cubed","3 large carrots, sliced","1 medium onion, diced","2 stalks celery, sliced","4 cups beef broth","2 tbsp tomato paste","1 tbsp Worcestershire sauce","3 cloves garlic, minced","1 tsp dried thyme","3 tbsp flour","2 tbsp olive oil","1 tsp salt","½ tsp pepper"],instructions:"Toss 2 lbs beef cubes with 3 tbsp flour, 1 tsp salt, and ½ tsp pepper. Heat 2 tbsp olive oil in a large Dutch oven over medium-high heat. Brown beef in batches, about 3 minutes per side. Remove and set aside. In the same pot, add 1 diced onion, 3 cloves minced garlic, and 2 sliced celery stalks. Cook 3-4 minutes. Stir in 2 tbsp tomato paste and cook 1 minute. Add 4 cups beef broth and 1 tbsp Worcestershire, scraping up browned bits. Return beef to the pot. Add 4 cubed potatoes, 3 sliced carrots, and 1 tsp thyme. Bring to a boil, then reduce heat to low. Cover and simmer 2-2½ hours until beef is fork-tender and the stew has thickened. Adjust seasoning and serve. Serves 6.",cat:"soup",time:"2.5 hrs",diff:"Medium",emoji:"🥩"},
{name:"Buffalo Chicken Dip",image:"",ingredients:["8 oz cream cheese, softened","2 cups shredded cooked chicken","½ cup hot sauce (like Frank's RedHot)","½ cup ranch dressing","1 cup shredded cheddar cheese","2 green onions, sliced"],instructions:"Preheat oven to 375°F. Spread 8 oz softened cream cheese in the bottom of a 9-inch baking dish. Layer 2 cups shredded chicken on top. Pour ½ cup hot sauce and ½ cup ranch dressing evenly over the chicken. Sprinkle 1 cup shredded cheddar over everything. Bake at 375°F for 20 minutes until bubbly and heated through. Garnish with sliced green onions. Serve hot with tortilla chips, celery sticks, or crackers. Serves 8.",cat:"appetizer",time:"30 min",diff:"Easy",emoji:"🔥"},
{name:"Pasta Salad",image:"",ingredients:["8 oz rotini pasta","1 cup cherry tomatoes, halved","1 cup diced cucumber","½ cup sliced black olives","1 bell pepper, diced","¼ cup diced red onion","½ cup crumbled feta cheese","½ cup Italian dressing"],instructions:"Cook 8 oz rotini pasta according to package directions. Drain and rinse under cold water until completely cool. In a large bowl, combine cooled pasta, 1 cup halved cherry tomatoes, 1 cup diced cucumber, ½ cup sliced olives, 1 diced bell pepper, ¼ cup diced red onion, and ½ cup crumbled feta. Pour ½ cup Italian dressing over everything and toss to coat. Cover and refrigerate at least 1 hour before serving. Toss again and adjust seasoning before serving. Serves 6.",cat:"salad",time:"20 min",diff:"Easy",emoji:"🥗"},
{name:"Waffles",image:"",ingredients:["2 cups all-purpose flour","2 tbsp sugar","1 tbsp baking powder","½ tsp salt","2 large eggs","1¾ cups milk","½ cup melted butter","1 tsp vanilla"],instructions:"Preheat waffle iron. Whisk 2 cups flour, 2 tbsp sugar, 1 tbsp baking powder, and ½ tsp salt in a large bowl. In a separate bowl, whisk 2 eggs, 1¾ cups milk, ½ cup melted butter, and 1 tsp vanilla. Pour wet into dry and stir until just combined — some lumps are OK. Pour about ¾ cup batter (or amount specified by your waffle iron) onto the preheated iron. Close and cook until golden and steam stops, about 3-5 minutes. Repeat with remaining batter. Serve with maple syrup, fresh berries, and whipped cream. Makes about 6 waffles.",cat:"breakfast",time:"20 min",diff:"Easy",emoji:"🧇"},
{name:"Loaded Nachos",image:"",ingredients:["1 bag (13 oz) tortilla chips","1 lb ground beef","1 packet taco seasoning","2 cups shredded cheddar cheese","¼ cup sliced jalapeños","½ cup sour cream","½ cup salsa","½ cup guacamole","¼ cup sliced black olives"],instructions:"Preheat oven to 400°F. Brown 1 lb ground beef in a skillet, drain fat. Add 1 packet taco seasoning and water per package directions. Simmer 5 minutes. Spread 13 oz tortilla chips in a single layer on a large sheet pan. Spoon seasoned beef evenly over chips. Top with 2 cups cheddar and ¼ cup sliced jalapeños. Bake 8-10 minutes until cheese is melted and bubbly. Remove from oven and top with ½ cup sour cream, ½ cup salsa, ½ cup guacamole, and ¼ cup sliced olives. Serve immediately. Serves 6.",cat:"appetizer",time:"25 min",diff:"Easy",emoji:"🧀"},
{name:"Chicken Pot Pie",image:"",ingredients:["2 cups cooked diced chicken","1 cup frozen peas","1 cup diced carrots","1 cup diced potatoes","½ cup diced onion","⅓ cup butter","⅓ cup flour","1¾ cups chicken broth","⅔ cup milk","1 tsp salt","¼ tsp pepper","½ tsp thyme","2 store-bought pie crusts"],instructions:"Preheat oven to 400°F. In a saucepan, boil 1 cup diced carrots and 1 cup diced potatoes until just tender, about 8 minutes. Drain. In a large pot, melt ⅓ cup butter over medium heat. Add ½ cup diced onion and cook 3 minutes. Whisk in ⅓ cup flour and cook 1 minute. Gradually stir in 1¾ cups broth and ⅔ cup milk. Cook, whisking constantly, until thickened, about 5 minutes. Stir in 2 cups diced chicken, cooked carrots and potatoes, 1 cup frozen peas, 1 tsp salt, ¼ tsp pepper, and ½ tsp thyme. Place 1 pie crust in a 9-inch pie dish. Pour in the filling. Top with the second crust, crimp edges, and cut 3-4 slits in the top. Bake at 400°F for 30-35 minutes until golden. Rest 10 minutes before serving. Serves 6.",cat:"dinner",time:"55 min",diff:"Medium",emoji:"🥧"},
{name:"Bruschetta",image:"",ingredients:["1 French baguette, sliced into ½-inch rounds","4 medium tomatoes, diced","¼ cup fresh basil, chopped","2 cloves garlic, minced (plus 1 clove for rubbing)","2 tbsp olive oil","1 tbsp balsamic vinegar","½ tsp salt","¼ tsp pepper"],instructions:"Dice 4 tomatoes and combine in a bowl with ¼ cup chopped basil, 2 cloves minced garlic, 2 tbsp olive oil, 1 tbsp balsamic vinegar, ½ tsp salt, and ¼ tsp pepper. Toss and let sit at room temperature 15-20 minutes so the flavors meld. Meanwhile, slice the baguette into ½-inch rounds. Brush with olive oil and toast under the broiler for 1-2 minutes per side until golden. Rub each toast lightly with a cut garlic clove. Spoon the tomato mixture generously onto each toast. Serve immediately. Makes about 20 pieces.",cat:"appetizer",time:"20 min",diff:"Easy",emoji:"🍅"},
{name:"Peanut Butter Banana Smoothie",image:"",ingredients:["1 frozen banana","2 tbsp peanut butter","1 cup milk","1 tbsp honey","½ tsp vanilla","4-5 ice cubes"],instructions:"Add 1 frozen banana (broken into chunks), 2 tbsp peanut butter, 1 cup milk, 1 tbsp honey, ½ tsp vanilla, and 4-5 ice cubes to a blender. Blend on high for 45-60 seconds until thick, smooth, and creamy. Pour into a tall glass. For a thicker shake, add another half banana or less milk. Serves 1.",cat:"drink",time:"5 min",diff:"Easy",emoji:"🍌"},
{name:"Garden Salad",image:"",ingredients:["4 cups mixed greens","1 medium tomato, diced","½ cucumber, sliced","¼ red onion, thinly sliced","1 medium carrot, shredded","½ cup croutons","ranch dressing to taste"],instructions:"Wash and dry 4 cups mixed greens. Toss in a large bowl with 1 diced tomato, ½ sliced cucumber, ¼ thinly sliced red onion, and 1 shredded carrot. Top with ½ cup croutons. Serve with ranch dressing on the side. Serves 2-4.",cat:"salad",time:"10 min",diff:"Easy",emoji:"🥗"},
{name:"Stuffed Peppers",image:"",ingredients:["6 large bell peppers","1 lb ground beef","1 cup cooked rice","1 medium onion, diced","3 cloves garlic, minced","1 can (15 oz) tomato sauce","1 cup shredded cheddar","1 tsp Italian seasoning","½ tsp salt","¼ tsp pepper"],instructions:"Preheat oven to 375°F. Cut tops off 6 bell peppers and remove seeds. Blanch peppers in boiling water 3 minutes, then drain upside down. Brown 1 lb ground beef with 1 diced onion and 3 cloves minced garlic in a skillet. Drain fat. Mix in 1 cup cooked rice, ½ can (about 7 oz) tomato sauce, ½ cup cheddar, 1 tsp Italian seasoning, ½ tsp salt, and ¼ tsp pepper. Fill each pepper with the mixture. Stand peppers upright in a baking dish. Pour remaining tomato sauce around the peppers. Cover with foil. Bake 30 minutes. Remove foil, top each pepper with remaining cheddar. Bake 5 more minutes uncovered until cheese melts. Serves 6.",cat:"dinner",time:"50 min",diff:"Medium",emoji:"🫑"},
{name:"Pumpkin Pie",image:"",ingredients:["1 can (15 oz) pumpkin puree","1 can (12 oz) evaporated milk","2 large eggs","¾ cup sugar","1 tsp cinnamon","½ tsp ginger","¼ tsp nutmeg","¼ tsp cloves","½ tsp salt","1 unbaked 9-inch pie crust"],instructions:"Preheat oven to 425°F. Whisk together 15 oz pumpkin puree, 2 eggs, ¾ cup sugar, 1 tsp cinnamon, ½ tsp ginger, ¼ tsp nutmeg, ¼ tsp cloves, and ½ tsp salt until smooth. Gradually stir in 12 oz evaporated milk until well combined. Pour filling into the unbaked 9-inch pie crust. Bake at 425°F for 15 minutes. Reduce temperature to 350°F and bake an additional 40-50 minutes until a knife inserted near the center comes out clean. The center may still jiggle slightly — it will set as it cools. Cool on a wire rack for 2 hours before serving. Serve with whipped cream. Serves 8.",cat:"dessert",time:"70 min",diff:"Medium",emoji:"🥧"},
{name:"Club Sandwich",image:"",ingredients:["3 slices bread (per sandwich)","3 slices deli turkey","2 slices ham","3 slices bacon, cooked","1 leaf lettuce","2-3 slices tomato","1 tbsp mayonnaise","1 slice cheddar cheese"],instructions:"Toast 3 slices of bread. Spread mayo on one side of each slice. On the first toast, layer turkey, lettuce, and tomato. Place second toast on top (mayo-side up). Layer ham, cooked bacon, and cheddar cheese. Top with the third toast (mayo-side down). Secure each quarter with a toothpick and cut into 4 triangles. Serve with chips or a side salad. Makes 1 sandwich.",cat:"lunch",time:"12 min",diff:"Easy",emoji:"🥪"},
{name:"Cheesy Garlic Biscuits",image:"",ingredients:["2 cups baking mix (like Bisquick)","¾ cup shredded cheddar cheese","⅔ cup milk","2 tbsp melted butter","½ tsp garlic powder","1 tbsp chopped parsley"],instructions:"Preheat oven to 450°F. Stir together 2 cups baking mix, ¾ cup cheddar, and ⅔ cup milk until a soft dough forms. Drop by heaping spoonfuls (about 10-12 biscuits) onto an ungreased baking sheet. Bake at 450°F for 8-10 minutes until golden on top. While biscuits bake, mix 2 tbsp melted butter, ½ tsp garlic powder, and 1 tbsp chopped parsley. Brush the garlic butter over the hot biscuits as soon as they come out of the oven. Serve warm. Makes 10-12 biscuits.",cat:"side",time:"18 min",diff:"Easy",emoji:"🧈"},
{name:"Chicken Wings",image:"",ingredients:["3 lbs chicken wings","4 tbsp melted butter","½ cup hot sauce (like Frank's RedHot)","½ tsp garlic powder","½ tsp salt","¼ tsp pepper","celery sticks for serving","ranch dressing for serving"],instructions:"Preheat oven to 400°F. Pat 3 lbs chicken wings dry with paper towels. Toss with ½ tsp garlic powder, ½ tsp salt, and ¼ tsp pepper. Spread in a single layer on a wire rack set over a baking sheet. Bake at 400°F for 45-50 minutes, flipping halfway through, until golden and crispy. In a large bowl, mix 4 tbsp melted butter and ½ cup hot sauce. Add the baked wings and toss to coat. Serve with celery sticks and ranch dressing. Serves 4-6.",cat:"appetizer",time:"55 min",diff:"Easy",emoji:"🍗"},
{name:"Cobb Salad",image:"",ingredients:["1 large head romaine lettuce, chopped","2 grilled chicken breasts, diced","6 slices bacon, cooked and crumbled","4 hard-boiled eggs, diced","2 avocados, diced","1 cup cherry tomatoes, halved","½ cup blue cheese crumbles","½ cup ranch dressing"],instructions:"Arrange chopped romaine on a large platter. In neat rows on top, arrange diced grilled chicken, crumbled bacon, diced hard-boiled eggs, diced avocados, halved cherry tomatoes, and blue cheese crumbles. Drizzle ranch dressing over the top or serve on the side. Toss just before eating. Serves 4.",cat:"salad",time:"25 min",diff:"Easy",emoji:"🥗"},
{name:"Minestrone Soup",image:"",ingredients:["6 cups vegetable broth","1 can (14 oz) diced tomatoes","1 can (15 oz) kidney beans, drained","1 medium zucchini, diced","2 medium carrots, diced","2 stalks celery, diced","1 medium onion, diced","3 cloves garlic, minced","½ cup small pasta (like ditalini)","2 tbsp fresh basil, chopped","¼ cup grated parmesan","1 tbsp olive oil","½ tsp salt","¼ tsp pepper"],instructions:"Heat 1 tbsp olive oil in a large pot over medium heat. Sauté 1 diced onion, 3 cloves minced garlic, 2 diced celery stalks, and 2 diced carrots for 5 minutes until softened. Add 6 cups vegetable broth, 14 oz diced tomatoes, 15 oz drained kidney beans, and 1 diced zucchini. Season with ½ tsp salt and ¼ tsp pepper. Bring to a boil, then reduce heat and simmer 15 minutes. Add ½ cup small pasta and cook 8-10 more minutes until pasta is tender. Stir in 2 tbsp chopped basil. Serve topped with grated parmesan. Serves 6.",cat:"soup",time:"40 min",diff:"Easy",emoji:"🍲"},
{name:"Chocolate Lava Cake",image:"",ingredients:["4 oz dark chocolate","½ cup butter","1 cup powdered sugar","2 whole eggs","2 egg yolks","6 tbsp all-purpose flour","1 tsp vanilla","pinch of salt","butter and cocoa for ramekins"],instructions:"Preheat oven to 425°F. Grease 4 ramekins (6 oz each) with butter and dust with cocoa powder. Melt 4 oz dark chocolate and ½ cup butter together in a microwave in 30-second intervals, stirring between. Whisk in 1 cup powdered sugar until smooth. Beat in 2 whole eggs and 2 egg yolks one at a time. Stir in 6 tbsp flour, 1 tsp vanilla, and a pinch of salt until just combined. Divide batter evenly among the 4 ramekins. Bake at 425°F for 12-14 minutes — the edges should be firm but the center should jiggle slightly. Let cool 1 minute, then carefully invert each onto a plate. The center should ooze with melted chocolate. Serve immediately. Serves 4.",cat:"dessert",time:"25 min",diff:"Hard",emoji:"🍫"},
{name:"Breakfast Burrito",image:"",ingredients:["2 large flour tortillas","4 large eggs, scrambled","4 slices bacon, cooked and crumbled","½ cup shredded cheddar cheese","¼ cup salsa","½ avocado, sliced","2 tbsp sour cream"],instructions:"Scramble 4 eggs in a buttered pan over medium heat until just set, about 3 minutes. Cook 4 slices bacon until crispy and crumble. Warm 2 tortillas in a dry skillet or microwave for 15 seconds. Down the center of each tortilla, layer half the scrambled eggs, crumbled bacon, ¼ cup cheddar, a few avocado slices, 2 tbsp salsa, and 1 tbsp sour cream. Fold the sides of the tortilla inward, then roll up tightly from the bottom. Cut in half if desired. Serves 2.",cat:"breakfast",time:"15 min",diff:"Easy",emoji:"🌯"},
{name:"Baked Potato",image:"",ingredients:["4 large russet potatoes","2 tbsp olive oil","1 tsp salt","4 tbsp butter","½ cup sour cream","1 cup shredded cheddar","4 slices bacon, cooked and crumbled","3 tbsp chopped chives","pepper to taste"],instructions:"Preheat oven to 400°F. Scrub 4 potatoes and dry well. Poke each potato 6-8 times with a fork. Rub each with olive oil and sprinkle with salt. Place directly on the oven rack. Bake at 400°F for 55-65 minutes until a knife slides easily into the center. Slice a cross in the top of each potato and squeeze the sides to open it up. Fluff the inside with a fork. Top each with 1 tbsp butter, 2 tbsp sour cream, ¼ cup cheddar, crumbled bacon, chives, and pepper. Serves 4.",cat:"side",time:"65 min",diff:"Easy",emoji:"🥔"},
{name:"Shrimp Scampi",image:"",ingredients:["1 lb large shrimp, peeled and deveined","12 oz linguine","3 tbsp butter","2 tbsp olive oil","5 cloves garlic, minced","½ cup dry white wine","3 tbsp fresh lemon juice","¼ tsp red pepper flakes","3 tbsp fresh parsley, chopped","¼ cup grated parmesan","½ tsp salt"],instructions:"Cook 12 oz linguine according to package directions. Reserve ½ cup pasta water before draining. In a large skillet, heat 2 tbsp olive oil and 1 tbsp butter over medium-high heat. Add 1 lb shrimp, season with ½ tsp salt. Cook 2 minutes per side until pink. Remove shrimp. Add 2 tbsp butter to the skillet. Sauté 5 cloves minced garlic and ¼ tsp red pepper flakes 30 seconds. Pour in ½ cup white wine and 3 tbsp lemon juice. Simmer 2 minutes. Add drained pasta, shrimp, and a splash of pasta water. Toss everything together. Garnish with parsley and parmesan. Serves 4.",cat:"dinner",time:"25 min",diff:"Medium",emoji:"🦐"},
{name:"Banana Smoothie Bowl",image:"",ingredients:["2 frozen bananas","3 tbsp milk","1 tbsp peanut butter","1 tbsp honey","¼ cup granola","¼ cup blueberries","1 tbsp chia seeds","1 tbsp coconut flakes"],instructions:"Blend 2 frozen bananas (broken into chunks), 3 tbsp milk, 1 tbsp peanut butter, and 1 tbsp honey in a blender until thick and smooth — it should be the consistency of soft-serve ice cream. Use a tamper or stop and stir if needed. Pour into a bowl. Top with ¼ cup granola, ¼ cup blueberries, 1 tbsp chia seeds, and 1 tbsp coconut flakes. Eat immediately with a spoon. Serves 1.",cat:"breakfast",time:"8 min",diff:"Easy",emoji:"🍌"},
{name:"Teriyaki Chicken",image:"",ingredients:["4 boneless skinless chicken thighs","¼ cup soy sauce","3 tbsp brown sugar","2 cloves garlic, minced","1 tsp fresh ginger, grated","1 tbsp rice vinegar","1 tsp sesame oil","1 tbsp cornstarch mixed with 2 tbsp water","2 cups steamed rice","2 cups steamed broccoli"],instructions:"In a small bowl, whisk ¼ cup soy sauce, 3 tbsp brown sugar, 2 cloves minced garlic, 1 tsp grated ginger, 1 tbsp rice vinegar, and 1 tsp sesame oil. Heat 1 tbsp oil in a skillet over medium-high heat. Cook 4 chicken thighs 5-6 minutes per side until golden and cooked through (165°F). Pour the teriyaki sauce into the skillet. Simmer 2 minutes. Add the cornstarch slurry and stir until the sauce thickens and turns glossy, about 1 minute. Slice chicken and serve over 2 cups steamed rice with 2 cups steamed broccoli. Spoon extra sauce over the top. Serves 4.",cat:"dinner",time:"30 min",diff:"Medium",emoji:"🍗"},
{name:"Caprese Salad",image:"",ingredients:["8 oz fresh mozzarella, sliced","3 medium tomatoes, sliced","½ cup fresh basil leaves","2 tbsp extra virgin olive oil","1 tbsp balsamic glaze","½ tsp salt","¼ tsp pepper"],instructions:"Slice 8 oz fresh mozzarella and 3 tomatoes into ¼-inch thick rounds. Alternate tomato and mozzarella slices on a serving plate, overlapping slightly. Tuck fresh basil leaves between the slices. Drizzle with 2 tbsp olive oil and 1 tbsp balsamic glaze. Season with ½ tsp salt and ¼ tsp pepper. Serve immediately at room temperature. Serves 4.",cat:"salad",time:"10 min",diff:"Easy",emoji:"🍅"},
{name:"Potato Wedges",image:"",ingredients:["4 large russet potatoes","3 tbsp olive oil","1 tsp paprika","½ tsp garlic powder","½ tsp onion powder","½ tsp salt","¼ tsp pepper","2 tbsp grated parmesan"],instructions:"Preheat oven to 425°F. Cut 4 potatoes into wedges (about 8 wedges per potato). Toss in a large bowl with 3 tbsp olive oil, 1 tsp paprika, ½ tsp garlic powder, ½ tsp onion powder, ½ tsp salt, and ¼ tsp pepper. Spread in a single layer on a parchment-lined baking sheet, skin side down. Bake 25-30 minutes, flipping halfway, until golden and crispy. Sprinkle 2 tbsp parmesan over the hot wedges and toss gently. Serves 4.",cat:"side",time:"35 min",diff:"Easy",emoji:"🥔"},
{name:"Penne Arrabbiata",image:"",ingredients:["1 lb penne pasta","1 can (28 oz) crushed tomatoes","4 cloves garlic, sliced thin","1 tsp red pepper flakes","3 tbsp olive oil","½ cup fresh basil, torn","¼ cup grated parmesan","1 tsp salt"],instructions:"Cook 1 lb penne according to package directions. Reserve ½ cup pasta water before draining. Heat 3 tbsp olive oil in a large skillet over medium heat. Add 4 cloves thinly sliced garlic and 1 tsp red pepper flakes. Cook 1-2 minutes until garlic is golden (not brown). Pour in 28 oz crushed tomatoes and 1 tsp salt. Simmer 15 minutes, stirring occasionally, until the sauce thickens slightly. Toss drained penne into the sauce with a splash of pasta water. Cook together 1-2 minutes. Serve topped with torn basil and parmesan. Serves 4-6.",cat:"dinner",time:"25 min",diff:"Easy",emoji:"🍝"},
{name:"Lemon Bars",image:"",ingredients:["1 cup butter, softened","2 cups flour (divided: 1½ for crust, ½ for filling)","½ cup powdered sugar (plus extra for dusting)","4 large eggs","1½ cups sugar","⅓ cup fresh lemon juice","1 tbsp lemon zest","1 tsp baking powder"],instructions:"Preheat oven to 350°F. Mix 1 cup softened butter, 1½ cups flour, and ½ cup powdered sugar until a crumbly dough forms. Press evenly into a greased 9x13 inch pan. Bake crust at 350°F for 15-18 minutes until lightly golden. Meanwhile, whisk together 4 eggs, 1½ cups sugar, ⅓ cup lemon juice, 1 tbsp lemon zest, ½ cup flour, and 1 tsp baking powder until smooth. Pour the lemon filling over the hot crust. Return to oven and bake 20-22 more minutes until the filling is set and no longer jiggly. Cool completely in the pan (at least 2 hours). Dust generously with powdered sugar before cutting into bars. Makes 24 bars.",cat:"dessert",time:"50 min",diff:"Medium",emoji:"🍋"},
{name:"Avocado Toast",image:"",ingredients:["2 slices thick bread","1 ripe avocado","1 tsp lemon juice","¼ tsp red pepper flakes","salt and pepper to taste","1 tsp olive oil","everything bagel seasoning (optional)"],instructions:"Toast 2 slices of thick bread until golden and crispy. Cut 1 avocado in half, remove pit, and scoop the flesh into a bowl. Add 1 tsp lemon juice, a pinch of salt and pepper, and mash with a fork to your preferred consistency. Spread the mashed avocado thickly onto each toast. Drizzle with 1 tsp olive oil. Sprinkle with ¼ tsp red pepper flakes and everything bagel seasoning if desired. Serve immediately. Serves 1-2.",cat:"breakfast",time:"5 min",diff:"Easy",emoji:"🥑"},
{name:"Chicken Soup with Rice",image:"",ingredients:["2 chicken breasts","¾ cup long-grain white rice","3 medium carrots, diced","2 stalks celery, diced","1 medium onion, diced","3 cloves garlic, minced","8 cups chicken broth","1 tsp dried thyme","2 tbsp fresh lemon juice","2 tbsp fresh parsley, chopped","1 tsp salt","½ tsp pepper"],instructions:"In a large pot, bring 8 cups broth to a boil. Add 2 chicken breasts, reduce heat, and simmer 20 minutes until cooked through. Remove chicken and shred with forks. In the same broth, add 1 diced onion, 3 cloves minced garlic, 2 diced celery stalks, and 3 diced carrots. Simmer 10 minutes. Add ¾ cup rice, shredded chicken, 1 tsp thyme, 1 tsp salt, and ½ tsp pepper. Simmer 18-20 more minutes until rice is tender. Stir in 2 tbsp lemon juice and 2 tbsp parsley. Serves 6.",cat:"soup",time:"50 min",diff:"Easy",emoji:"🍲"},
{name:"Snickerdoodles",image:"",ingredients:["½ cup softened butter","¾ cup sugar","1 large egg","1 tsp vanilla","1½ cups all-purpose flour","1 tsp cream of tartar","½ tsp baking soda","¼ tsp salt","2 tbsp sugar (for rolling)","2 tsp cinnamon (for rolling)"],instructions:"Preheat oven to 375°F. Cream ½ cup butter and ¾ cup sugar until fluffy. Beat in 1 egg and 1 tsp vanilla. Whisk together 1½ cups flour, 1 tsp cream of tartar, ½ tsp baking soda, and ¼ tsp salt. Add dry ingredients to wet and mix until just combined. In a small bowl, mix 2 tbsp sugar and 2 tsp cinnamon. Roll dough into 1-inch balls and roll each in the cinnamon-sugar mixture. Place 2 inches apart on parchment-lined baking sheets. Bake at 375°F for 9-11 minutes until the edges are set but centers are still soft. Cool on sheet 3 minutes before transferring. Makes about 24 cookies.",cat:"dessert",time:"25 min",diff:"Easy",emoji:"🍪"},
{name:"Taco Salad",image:"",ingredients:["1 lb ground beef","1 packet taco seasoning","1 head romaine lettuce, chopped","2 cups tortilla chips, crushed","1 cup shredded cheddar cheese","1 medium tomato, diced","1 can (15 oz) black beans, drained","1 cup corn kernels","½ cup sour cream","½ cup salsa"],instructions:"Brown 1 lb ground beef in a skillet, drain fat. Add 1 packet taco seasoning and water per package directions. Simmer 5 minutes. Chop 1 head romaine lettuce and divide among 4 bowls. Top each with seasoned beef, crushed tortilla chips, cheddar, diced tomato, black beans, and corn. Dollop with sour cream and salsa. Serves 4.",cat:"salad",time:"20 min",diff:"Easy",emoji:"🥗"},
{name:"Apple Pie",image:"",ingredients:["2 store-bought pie crusts","6 medium apples, peeled and sliced","¾ cup sugar","2 tbsp flour","1 tsp cinnamon","¼ tsp nutmeg","1 tbsp lemon juice","2 tbsp cold butter, cubed","1 egg beaten with 1 tbsp water (egg wash)"],instructions:"Preheat oven to 375°F. Toss 6 sliced apples with ¾ cup sugar, 2 tbsp flour, 1 tsp cinnamon, ¼ tsp nutmeg, and 1 tbsp lemon juice. Place 1 pie crust in a 9-inch pie dish. Pour in the apple filling and dot the top with 2 tbsp cubed cold butter. Place the second crust on top. Crimp and seal the edges. Cut 4 slits in the top for steam. Brush the top with egg wash. Bake at 375°F for 45-50 minutes until the crust is golden brown and the filling is bubbling through the slits. If the edges brown too fast, cover them with foil. Cool at least 2 hours before slicing. Serves 8.",cat:"dessert",time:"60 min",diff:"Medium",emoji:"🥧"},
{name:"Ham & Cheese Sliders",image:"",ingredients:["12 Hawaiian rolls (1 package)","¾ lb deli ham, sliced","12 slices Swiss cheese","¼ cup melted butter","1 tbsp Dijon mustard","1 tsp Worcestershire sauce","1 tsp poppy seeds","½ tsp onion powder"],instructions:"Preheat oven to 350°F. Slice the entire block of 12 Hawaiian rolls in half horizontally (keep them connected). Place the bottom half in a greased 9x13 inch baking dish. Layer ¾ lb ham and 12 slices Swiss cheese on the bottom halves. Place the top half of rolls back on. In a small bowl, mix ¼ cup melted butter, 1 tbsp Dijon mustard, 1 tsp Worcestershire, 1 tsp poppy seeds, and ½ tsp onion powder. Pour evenly over the tops of the rolls. Cover with foil. Bake at 350°F for 15 minutes covered. Remove foil and bake 5 more minutes until cheese is melted and tops are golden. Pull apart and serve. Makes 12 sliders.",cat:"appetizer",time:"25 min",diff:"Easy",emoji:"🥪"},
{name:"Biscuits and Gravy",image:"",ingredients:["1 can (16 oz) refrigerated biscuits","1 lb pork sausage","¼ cup all-purpose flour","3 cups milk","½ tsp salt","½ tsp pepper"],instructions:"Bake biscuits according to package directions. While biscuits bake, crumble 1 lb pork sausage into a large skillet over medium heat. Cook 8-10 minutes until browned and cooked through — do not drain the fat. Sprinkle ¼ cup flour over the sausage and stir for 1 minute to cook the flour. Slowly pour in 3 cups milk, stirring constantly to avoid lumps. Cook 5-7 minutes, stirring frequently, until the gravy thickens to your desired consistency. Season with ½ tsp salt and ½ tsp pepper. Split biscuits in half and spoon sausage gravy generously over the top. Serves 4-6.",cat:"breakfast",time:"25 min",diff:"Easy",emoji:"🍞"},
{name:"Creamy Tomato Basil Pasta",image:"",ingredients:["12 oz penne pasta","2 cups cherry tomatoes, halved","4 cloves garlic, minced","1 cup heavy cream","½ cup grated parmesan","¼ cup fresh basil, torn","2 tbsp olive oil","½ tsp salt","¼ tsp pepper","¼ tsp red pepper flakes"],instructions:"Cook 12 oz penne according to package directions. Reserve ½ cup pasta water. Heat 2 tbsp olive oil in a large skillet over medium heat. Add 4 cloves minced garlic and cook 30 seconds. Add 2 cups halved cherry tomatoes and cook 4-5 minutes until they blister and soften. Pour in 1 cup heavy cream and simmer 3 minutes. Stir in ½ cup parmesan, ½ tsp salt, ¼ tsp pepper, and ¼ tsp red pepper flakes. Add drained penne and toss in the sauce, adding a splash of pasta water if needed. Fold in ¼ cup torn basil. Serve immediately. Serves 4.",cat:"dinner",time:"20 min",diff:"Easy",emoji:"🍝"},
{name:"Peach Cobbler",image:"",ingredients:["6 cups sliced peaches (fresh or canned, drained)","¾ cup sugar (divided: ½ cup for filling, ¼ cup for batter)","1 tsp cinnamon","½ cup butter","1 cup all-purpose flour","1 tbsp baking powder","1 cup milk","1 tsp vanilla"],instructions:"Preheat oven to 350°F. Toss 6 cups sliced peaches with ½ cup sugar and 1 tsp cinnamon. Melt ½ cup butter in a 9x13 inch baking dish in the oven. In a bowl, mix 1 cup flour, ¼ cup sugar, 1 tbsp baking powder, 1 cup milk, and 1 tsp vanilla until smooth. Pour the batter over the melted butter in the dish — do NOT stir. Spoon the sugared peaches evenly over the batter — do NOT stir. Bake at 350°F for 40-45 minutes until the batter rises up around the peaches and turns golden brown. Serve warm, ideally with a scoop of vanilla ice cream. Serves 8.",cat:"dessert",time:"55 min",diff:"Easy",emoji:"🍑"},
{name:"Greek Salad",image:"",ingredients:["1 large cucumber, diced","3 medium tomatoes, diced","½ red onion, thinly sliced","½ cup Kalamata olives","4 oz crumbled feta cheese","3 tbsp extra virgin olive oil","1½ tbsp lemon juice","1 tsp dried oregano","½ tsp salt","¼ tsp pepper"],instructions:"Dice 1 cucumber and 3 tomatoes into bite-sized pieces. Thinly slice ½ red onion. Combine in a large bowl with ½ cup Kalamata olives and 4 oz crumbled feta. In a small bowl, whisk 3 tbsp olive oil, 1½ tbsp lemon juice, 1 tsp oregano, ½ tsp salt, and ¼ tsp pepper. Pour dressing over the salad and toss gently. Serve immediately or refrigerate up to 1 hour. Serves 4.",cat:"salad",time:"10 min",diff:"Easy",emoji:"🥗"},
{name:"S'mores Dip",image:"",ingredients:["2 cups chocolate chips","3 cups mini marshmallows","8 graham crackers","1 tbsp butter"],instructions:"Preheat oven to 450°F. Grease a 10-inch cast iron skillet or oven-safe dish with 1 tbsp butter. Spread 2 cups chocolate chips evenly in the bottom. Top with 3 cups mini marshmallows in an even layer. Bake at 450°F for 7-8 minutes until the marshmallows are puffed and golden brown on top. Serve immediately with 8 graham crackers broken into dipping sticks. Serves 6.",cat:"dessert",time:"12 min",diff:"Easy",emoji:"🔥"},
{name:"Honey Garlic Chicken",image:"",ingredients:["4 boneless skinless chicken thighs","¼ cup honey","3 tbsp soy sauce","4 cloves garlic, minced","1 tbsp butter","½ tsp ginger","2 cups steamed rice","2 cups steamed green beans"],instructions:"Mix ¼ cup honey, 3 tbsp soy sauce, 4 cloves minced garlic, and ½ tsp ginger in a small bowl. Season 4 chicken thighs with salt and pepper. Melt 1 tbsp butter in a skillet over medium-high heat. Sear chicken 5 minutes per side until golden. Pour the honey garlic sauce into the skillet. Reduce heat to medium and simmer 8-10 minutes, spooning sauce over chicken, until chicken is cooked through (165°F) and the sauce is thick and sticky. Serve over steamed rice with green beans. Spoon extra sauce over everything. Serves 4.",cat:"dinner",time:"30 min",diff:"Medium",emoji:"🍯"},
{name:"Strawberry Shortcake",image:"",ingredients:["6 biscuits (homemade or store-bought)","2 cups fresh strawberries, sliced","¼ cup sugar","1½ cups whipped cream","1 tsp vanilla"],instructions:"Slice 2 cups strawberries and toss with ¼ cup sugar in a bowl. Let sit at room temperature for 20-30 minutes until the strawberries release their juices (this is called macerating). Whip 1½ cups heavy cream with 1 tsp vanilla until soft peaks form (or use canned whipped cream). Split 6 biscuits in half horizontally. Place the bottom halves on plates. Spoon macerated strawberries and their juices over the bottoms. Add a generous dollop of whipped cream. Place the biscuit tops on and add more strawberries and cream. Serves 6.",cat:"dessert",time:"30 min",diff:"Easy",emoji:"🍓"},
{name:"Vegetable Soup",image:"",ingredients:["6 cups vegetable broth","3 medium potatoes, diced","3 carrots, diced","2 stalks celery, diced","1 medium onion, diced","2 cloves garlic, minced","1 cup green beans, cut into 1-inch pieces","1 cup corn kernels","1 can (14 oz) diced tomatoes","1 tsp dried thyme","2 bay leaves","1 tsp salt","½ tsp pepper"],instructions:"Heat 1 tbsp olive oil in a large pot over medium heat. Sauté 1 diced onion, 2 cloves minced garlic, and 2 diced celery stalks for 4-5 minutes. Add 6 cups broth, 14 oz diced tomatoes (with juices), 3 diced potatoes, 3 diced carrots, 1 cup green beans, 1 cup corn, 1 tsp thyme, and 2 bay leaves. Season with 1 tsp salt and ½ tsp pepper. Bring to a boil, then reduce heat and simmer 25-30 minutes until all vegetables are tender. Remove bay leaves. Taste and adjust seasoning. Serves 6-8.",cat:"soup",time:"40 min",diff:"Easy",emoji:"🥕"},
{name:"Iced Tea",image:"",ingredients:["4 tea bags (black tea)","4 cups boiling water","½ cup sugar","4 cups cold water","ice","lemon slices","fresh mint sprigs"],instructions:"Bring 4 cups water to a boil. Remove from heat and add 4 tea bags. Steep 5 minutes (no longer or it will be bitter). Remove tea bags, squeezing gently. Stir in ½ cup sugar while the tea is still warm until fully dissolved. Pour into a large pitcher and add 4 cups cold water. Stir well and refrigerate until cold, at least 1 hour. Serve over ice with lemon slices and fresh mint. Serves 6-8.",cat:"drink",time:"15 min",diff:"Easy",emoji:"🧊"},
{name:"Hash Brown Casserole",image:"",ingredients:["1 bag (30 oz) frozen shredded hash browns","1 can (10.5 oz) cream of mushroom soup","1 cup sour cream","2 cups shredded cheddar cheese","¼ cup melted butter","½ cup diced onion","½ tsp salt","¼ tsp pepper","2 cups crushed cornflakes","3 tbsp melted butter (for topping)"],instructions:"Preheat oven to 350°F. Thaw 30 oz hash browns slightly. In a large bowl, mix hash browns, 1 can cream of mushroom soup, 1 cup sour cream, 2 cups cheddar, ¼ cup melted butter, ½ cup diced onion, ½ tsp salt, and ¼ tsp pepper. Spread into a greased 9x13 inch baking dish. In a small bowl, toss 2 cups crushed cornflakes with 3 tbsp melted butter. Sprinkle the cornflake topping evenly over the casserole. Bake at 350°F for 45-50 minutes until bubbly and the top is golden and crispy. Let rest 10 minutes before serving. Serves 8-10.",cat:"breakfast",time:"60 min",diff:"Easy",emoji:"🥔"},
];